import{_ as t,o,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"security.md","filePath":"security.md","lastUpdated":1784187737000}'),s={name:"security.md"};function n(i,e,c,d,l,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="security-model" tabindex="-1">Security model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security model&quot;">​</a></h2><p>The library only ever reads or writes to an iframe document the browser already considers <strong>same-origin</strong>. It does not attempt to bypass the same-origin policy, and it cannot access cross-origin content — the browser itself enforces that boundary.</p><p>Supported:</p><ul><li><code>srcdoc</code> documents</li><li><code>about:blank</code></li><li>Same-origin URLs</li></ul><p>Not supported, and out of scope for this library:</p><ul><li>Cross-origin iframe injection</li><li>Browser security bypasses</li><li>Third-party document access</li></ul><p>Attempting to access a cross-origin document raises a typed <code>IframeError</code> with <code>reason: &#39;cross-origin&#39;</code> rather than an uncaught <code>SecurityError</code>.</p><h2 id="recommended-sandbox" tabindex="-1">Recommended <code>sandbox</code> <a class="header-anchor" href="#recommended-sandbox" aria-label="Permalink to &quot;Recommended `sandbox`&quot;">​</a></h2><p>The component defaults to:</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sandbox=&quot;allow-scripts allow-same-origin&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This allows injected scripts to run and keeps the frame same-origin (required for <code>contentDocument</code> access), while still applying the rest of the sandbox&#39;s default restrictions (no top-level navigation, no popups, no forms, unless separately allowed). Only relax the <code>sandbox</code> attribute for content you trust.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>allow-scripts</code> together with <code>allow-same-origin</code> is a well-known combination that, for a <strong>truly untrusted</strong> cross-origin document, can allow the sandbox to be undermined. This library is designed for same-origin previews of content you or your organization control (report rendering, CMS previews, internal tools) — it is not a sandbox for arbitrary third-party or user-submitted HTML.</p></div><h2 id="asset-governance" tabindex="-1">Asset governance <a class="header-anchor" href="#asset-governance" aria-label="Permalink to &quot;Asset governance&quot;">​</a></h2><p>Only inject assets you trust. Recommended controls for enterprise deployments:</p><ul><li><strong>URL allow-lists</strong> — validate <code>cssUrls</code>/<code>jsUrls</code> against a known-good list before passing them as props.</li><li><strong>Content Security Policy</strong> — set an appropriate CSP on the iframe&#39;s document and pass a matching <code>nonce</code> via <code>InjectionOptions</code> for inline <code>&lt;style&gt;</code>/<code>&lt;script&gt;</code> tags.</li><li><strong>Audit logging</strong> — listen to the <code>injected</code> and <code>error</code> events and forward them to your logging pipeline.</li><li><strong>Code review</strong> — treat CSS/JS strings passed into this component the same as any other code that will execute in your users&#39; browsers.</li></ul><h2 id="error-types" tabindex="-1">Error types <a class="header-anchor" href="#error-types" aria-label="Permalink to &quot;Error types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Reason</th><th>Meaning</th></tr></thead><tbody><tr><td><code>cross-origin</code></td><td>The iframe document could not be accessed due to origin policy.</td></tr><tr><td><code>document-unavailable</code></td><td>The iframe isn&#39;t mounted yet, or has no accessible document.</td></tr><tr><td><code>injection-failed</code></td><td>Document access succeeded, but creating/inserting the element failed.</td></tr></tbody></table><p>All three surface through the <code>error</code> event and via <code>onError</code> callbacks on <code>useIframeInjection</code>, so a host application can react without wrapping calls in try/catch itself.</p>',19)])])}const m=t(s,[["render",n]]);export{h as __pageData,m as default};
